      queryFetchStuff(
        variables?: {},
        resultSelector: string | ((qb: StringModelSelector) => StringModelSelector) = stringModelPrimitives.toString(),
        options: QueryOptions = {}
      ) {
        return self.query<{ fetchStuff: StringModelType[] }>(
          `query fetchStuff { fetchStuff {
